INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8104817','Tribute львівським трамваям','Музика: Іван Нишпора Слова: Мар''яна Масюк. Виконує: Тарасова ніч','uk','ukraine_1991',NULL,NULL,'http://tarasovanich.narod.ru',NULL,'Трамваї ідуть вгору-вниз,
Везуть, ховаючи сюрприз,
Життів і доль пахуче гроно.
Трамваї їдуть тут і там,
Питають в перехожих брам
Дорогу до кінця мандрівки.

Приспів:
Трамваї ідуть колом-колом,
На зустріч радості і горю.
Чужих думок і снів слідам,
Трамваї їдуть тут і там.

Трамваї їдуть у далеко,
Не знаю чи вернуться де то,
Мріями заховані зупинки.
Трамваї їдуть і ховають,
Трамваї їдуть і не знають,
Як відірватись від землі.

Приспів.

І полетіти над дахами,
Над стежками, і над птахами
Туди, де падає зоря,
Проміння сонця і моря.','[''pisni.org.ua'', ''cat:manrivni'', ''Пісні на мандрівну тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8104817'), datetime('now')),datetime('now'));
