INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8106013','Поведу коника','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'http://www.pisennyk.kgb.pl/',NULL,'1. Поведу коника на зелені лучки,     a E7 a
Поведу коника на зелені лучки,     a E7 a
Сам піду до милой стиха-помалючки  C F G C a C
Сам піду до милой стиха-помалючки. C G G C E7 a

2. Бо вона так думат, же єй не любую,
А я за недовго взяти єй рихтую.

3. Як собі заспівам на вроним коничку.
Мила заплакала, як брала водичку.

4. Не плач, мила, не плач, не на війну іду,
Лем тоді заплачеш, як до тя не прийду.

5. Уж сонечко зашло за високу гору,
Засвітив місяцьок до нашого двору.

6. Засвіть, мій мйсяцю, на вузьку дражечку.
Піду посмотрити свою фраїрочку.','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8106013'), datetime('now')),datetime('now'));
