INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8113676','Ой, не жалуй, моя мила, що я п''ю','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'http://www.karpaty.lviv.ua, джерело матеріалу: Малова-Малкович П. М. "З карпатських джерел": фольклорно-етнографічеий нарис. - Чернівці: Місто, 2004. - 176 с.',NULL,'Ой, не жалуй, моя мила, що я п''ю,
Тогди будеш жалувати, як я вмру.

Тогди будеш жалувати, плакати,
Як я буду в темнім гробі лежати.

Ой, зазнаєш, моя мила, гаразди,
Як то тяжко в світі жити без ґазди.

Треба хліба, треба соли до хати,
Нема кому бідній вдові встарати.

- Ой, уставай, мій миленький, встань, серце,
Стоїть твоя горівочка та й винце.

- Ой, пий, мила, чорнобрива, пий сама,
Чому-с мені не давала за життя?','[''pisni.org.ua'', ''cat:socialno-pobutovi'', ''Соціально-побутові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8113676'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8113676','Ой, не жалуй, моя мила, що я п''ю','Ой, не жалуй, моя мила, що я п''ю,
Тогди будеш жалувати, як я вмру.

Тогди будеш жалувати, плакати,
Як я буду в темнім гробі лежати.

Ой, зазнаєш, моя мила, гаразди,
Як то тяжко в світі жити без ґазди.

Треба хліба, треба соли до хати,
Нема кому бідній вдові встарати.

- Ой, уставай, мій миленький, встань, серце,
Стоїть твоя горівочка та й винце.

- Ой, пий, мила, чорнобрива, пий сама,
Чому-с мені не давала за життя?');
