INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_811052','На острові чекання','Музика: В''ячеслав Хурсенко Слова: В''ячеслав Хурсенко','uk','ukraine_1991',NULL,NULL,NULL,NULL,'О плями чорно-білі у щоденному житті,
Лишилося помріяти й збагнути — не святі.
Як мало і багато треба мати поміж тим,
Щоб жити мудрим старцем і злетіти молодим.

А завтра знову завтра знову кома на кінці,
І трубка телефонна у схвильованій руці,
Ти знову згубиш слово і у прірву піде час
Ця пауза мовчання стане приспівом для нас!

Приспів:
Та крутиться Земля,
Щаслива мить тікає,
Її не здоженеш,
Якщо життя немає.
Поклич мене любов
У подорож кохання,
Я так давно живу
На острові чекання.

Я хочу гріти сутінки не краденим вогнем,
Змінити кому крапкою для нових світлих тем.
Я всі найкращі помисли з тобою уявлю,
Бо я іще надіюся, бо я іще люблю.

Як хочеться зануритись у те чого нема,
Не чути ком зі смиком і любити не дарма,
Як хочеться із друзями провадити свята
І знати, що людина із тобою саме та!

Приспів:
Та крутиться Земля,
Щаслива мить тікає,
Її не здоженеш,
Якщо життя немає.
Поклич мене любов
У подорож кохання,
Я так давно живу
На острові чекання.','[''pisni.org.ua'', ''cat:philosophic'', ''Філософські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_811052'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_811052','На острові чекання','О плями чорно-білі у щоденному житті,
Лишилося помріяти й збагнути — не святі.
Як мало і багато треба мати поміж тим,
Щоб жити мудрим старцем і злетіти молодим.

А завтра знову завтра знову кома на кінці,
І трубка телефонна у схвильованій руці,
Ти знову згубиш слово і у прірву піде час
Ця пауза мовчання стане приспівом для нас!

Приспів:
Та крутиться Земля,
Щаслива мить тікає,
Її не здоженеш,
Якщо життя немає.
Поклич мене любов
У подорож кохання,
Я так давно живу
На острові чекання.

Я хочу гріти сутінки не краденим вогнем,
Змінити кому крапкою для нових світлих тем.
Я всі найкращі помисли з тобою уявлю,
Бо я іще надіюся, бо я іще люблю.

Як хочеться зануритись у те чого нема,
Не чути ком зі смиком і любити не дарма,
Як хочеться із друзями провадити свята
І знати, що людина із тобою саме та!

Приспів:
Та крутиться Земля,
Щаслива мить тікає,
Її не здоженеш,
Якщо життя немає.
Поклич мене любов
У подорож кохання,
Я так давно живу
На острові чекання.');
