INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_810910','Україна. Рок-н-рол *','(Моя Україна). Слова: Зеновій Филипчук. Виконує: Віка Врадій','uk','ukraine_1991',NULL,NULL,'Пісневир: Молодіжний співаник.— Львів, 2001',NULL,'Я також вже маю державу, і вільно живу, і щасливо.
Я тиждень працюю на каву, два тижні працюю на пиво.
Піду і позичу в сусіда на свята вина і хлібину.
Забули коли добре їли, а, бачите, ще не зомліли.

Приспів:
Моя Україна з горя почорніла,
Тяжко заробляє, але ще співає
Рок-н-рол!

Не треба мені говорити, як добре живеться у Штатах.
Я знаю — двері відкриті, там наших лишилось багато.
Дощі заливають гайвеї, птахи відлітають із дому.
Не знаю, чи зможу без неї навіть в раю золотому.

Приспів:
Моя Україна з горя почорніла,
Але у неділю сорочина біла.
Моя Україна з горя почорніла,
Тяжко заробляє, але ще співає
Рок-н-рол!','[''pisni.org.ua'', ''cat:emigration'', ''Пісні про еміґрацію'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_810910'), datetime('now')),datetime('now'));
