INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_810756','За пiчкою','(калибєльная)','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'За пічкою цвіркун сюрчить
Синочок мій іще не спить
Там за вікном морозяно
Сяє там небо зоряно

Коли нема ні крихтоньки
Глянь-но на місяць зіроньки
Ясно на небі сяють
В човнику пропливають

