INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8118154','Виходь, народе','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,NULL,'Співаник УПА. Борці за волю України. упор. О.Бобикевич, Ю.Лаврівський, О.Плешкевич та ін. Львів: Меморіал. 1992. - 190 с.',NULL,'Виходь, виходь, народе, з тюрм,
Туди, де вже воля витає,
Де носять в халявах свячені ножі,
Де полум''я помсти палає.

Вже пісня трембіти громами гуде,
Нових гайдамаків в бій святий веде.
Ця пісня — не кволе ридання —
Це зов, це зов до повстання!

Вставай, вставай народе мій,
Свобода народам — людині!
Зі Сходу вже сяє Тризуб золотий,
Сіятиме вічно від нині.

Вже пісня трембіти...

Дрижи, дрижи проклятий кат,
Ще мент і утопишся в крові.
Мов буря народна стихія гряде,
І рве вже залізні окови.

Вже пісня трембіти громами гуде,
Нових гайдамаків в бій святий веде,
Настане всенародна згода,
Свобода народам, свобода!','[''pisni.org.ua'', ''cat:himny-marshi'', ''cat:povstanski'', ''Гимни та марші'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8118154'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8118154','Виходь, народе','Виходь, виходь, народе, з тюрм,
Туди, де вже воля витає,
Де носять в халявах свячені ножі,
Де полум''я помсти палає.

Вже пісня трембіти громами гуде,
Нових гайдамаків в бій святий веде.
Ця пісня — не кволе ридання —
Це зов, це зов до повстання!

Вставай, вставай народе мій,
Свобода народам — людині!
Зі Сходу вже сяє Тризуб золотий,
Сіятиме вічно від нині.

Вже пісня трембіти...

Дрижи, дрижи проклятий кат,
Ще мент і утопишся в крові.
Мов буря народна стихія гряде,
І рве вже залізні окови.

Вже пісня трембіти громами гуде,
