INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8118312','У повстанцях','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,NULL,'Співаник УПА. Борці за волю України. упор. О.Бобикевич, Ю.Лаврівський, О.Плешкевич та ін. Львів: Меморіал. 1992. - 190 с.',NULL,'А хто хоче воювати
Той до УПА хай іде,
Кращих друзів й Командирів
Він у світі не найде.

Приспів:
У повстанцях добре є,
Все лісами ходиться,
І не спиться і не їсться,
Часом трохи і боїться,
Та це все ніщо, гей!

Був час, де ми приглядались,
Яке в нас життя було,
Не забудемо ми того,
Бо з нас вже військо.

Приспів.

Ми у бою завжди сміло
На всіх ворогів ідем,
Люблять нас дівчата наші —
Кращих ніде не найдем!

Приспів.','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8118312'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8118312','У повстанцях','А хто хоче воювати
