INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_811979','Колір чорний *','Слова: Степан Руданський. Виконує: Василь Триліс, Ольга Богомолець','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Щоб співати Колір Чорний,
Взяв би голос твій
І тобі одній покорний
Я співаю Колір Чорний
Бо то Колір мій,
Бо то Колір мій.

В Чорну Днину мене Мати
На світ привела
Чорні очі мені дала,
Чорні думи вколихала,
Ой чорні як Ніч
Як Осіння Ніч

Ох, ніхто вже не згадає
Нишком про мене,
І дівчина не пригорне,
Не згадає очі чорні
І не спом''яне,
І не спом''яне.

Щоб співати Колір Чорний
Взяв би голос Твій
І тобі одній покорний
Я співаю Колір Чорний
Бо то колір мій,
Бо то колір мій.    Аудіо (повна версія, 96 kbps)','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_811979'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_811979','Колір чорний *','Щоб співати Колір Чорний,
