INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8116654','Ой, запив козак','Українська народна пісня. Виконує: Григорій Китастий','uk','ukraine_before_1917',NULL,NULL,'Українські пісні з нотами. Збірник перший / упорядник П.Ф. Бунт, В. Шаравський. Київ. Видавниче товариство "Час", 1929.',NULL,'Ой, запив козак, запив, ой, та запив, загулявся,
А його кінь вороний та на стайні застоявся.

Ой, ти коню ж мій, коню вороненький,
Та коню вороненький, товаришу вірненький.

Ой, порадь мене, коню, де ми будем ніч ночувати,
Де ми будем ніч ночувати, хто нам буде постіль слати.

Переночуєм нічку в вишневому садочку,
Переночуєм другу у темненькому лугу.

Переночуєм другу у темненькому лугу,
Переночуєм третю в чистім степу, край дороги.

Переночуєм третю в чистім степу при дорозі,
Ой, в степу при дорозі та на лютому морозі.','[''pisni.org.ua'', ''cat:kozacki'', ''cat:socialno-pobutovi'', ''Козацькі пісні'', ''Соціально-побутові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8116654'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8116654','Ой, запив козак','Ой, запив козак, запив, ой, та запив, загулявся,
А його кінь вороний та на стайні застоявся.

