INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8118307','Дівчино, голубко','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,NULL,'Співаник УПА. Борці за волю України. упор. О.Бобикевич, Ю.Лаврівський, О.Плешкевич та ін. Львів: Меморіал. 1992. - 190 с.',NULL,'Дівчино голубко, присядь біля мене,
Хай тебе пригорну ще раз,
Нехай поцілую, обнявши востаннє,
Бо може заплачеш по нас.

Бо вже відходжу я на Волинь з друзями,
Всіх нас туди кличе наказ,
Щоб в УПА боротись за волю Вкраїни,
До зброї там кличуть всіх нас.

На горі могила, тризуб ввесь в прапорах,
А хрест березовий в квітках,
Три лави повстанців в стіп гробу героїв,
Присягу складають всі враз.

А дзвони в дзвіниці все грають, як сурми
Присягу повстанську несуть,
Від узгір Кавказу, до срібного Сяну,
Це марші бойові на путь.

Упала команда — тверда і рішуча: —
"До зброї повстанці, вперід!"
А сонце криваво понад гору знялось,
Сніжок шляхи стелить на схід.

Від''їхали друзі, по селах затихло,
Вертають дівчата до хат,
Повстанськую пісню лиш вітер доносить
З весною ми вернем до вас.','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8118307'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8118307','Дівчино, голубко','Дівчино голубко, присядь біля мене,
