INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8127312','Колядка','Музика: Журборіз Слова: Володимир Скоробський. Виконує: Журборіз','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Знову ніч, чарівна ніч, і радість у оселі,
Радіє Діва Марія, радіє на постелі.
Зійшла зоря і пастушки зустріли у яскині
Народження Дитяточка і Божої дитини.

Приспів:
Радій, радій, вкраїнський край, |
Радійте, добрі люди!            |
Стрічай, стрічай народження     |
Ісусика повсюди.                | (2)

Лиш пастушки та янголи у таємниці ночі
Вітали Діву Марію і Дитяточко Боже,
Зійшла зоря в зимову ніч і три царі вклонились
Дитяті Божому, дари у ясла положили.

Приспів.

Нехай Бог всіх благословить з небесної яскині
І мати Діва Марія попросить за нас Сина.
Складімо три дари йому - Любов, Надію, Віру,
Хай Божий край, вкраїнський вкрай співає Богу нині.

Радій, радій, вкраїнський край, |
Хай буде щастя й воля!          |
Любов і Віра у серцях,          |
Надія лиш на Бога!              | (2)

Зимова ніч, чарівна ніч...','[''pisni.org.ua'', ''cat:shchedrivky'', ''cat:suchasni-pisni-rizdvo'', ''Щедрівки'', ''Сучасні пісні про Різдвяні свята'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8127312'), datetime('now')),datetime('now'));
