INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_812552','У райськім саду','(Яворина). Музика: Степан Гіга Слова: Степан Галябарда. Виконує: Степан Гіга','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Я на світі прожив, наче спалах зорі на світанні,
Наче крапля роси, наче крик журавля - тільки мить.
Я не вірив ніяк, що й до мене прийде день останній,
І в жертовнім вогні моє серце на попіл згорить.
Я ж так щедро кохав, я так вірив у зорі і очі,
І душею своєю я вас, як умів, причащав.
Але видно Господь мені краще життя напророчив,
І до себе забрав, щоб у райськім саду я співав.
Приспів:
На могилі моїй посадіть молоду яворину,
І не плачте за мною, за мною заплаче рідня.
Я любив вас усіх, та найбільше любив Україну,
Певно, в цьому і є та найважча провина моя.
Хай душа переселиться в дивний той рай потойбічний,
Де таких, як і я, назліталася ціла сім''я.
Тільки нащо мені ті блаженства розкішні і вічні,
Як мені не всміхнеться донька-сиротинка моя.
У далеких світах якось раптом усе я покину,
Бо ввійде мені в душу сльозиною і чебрецем,
І додому хоч вітром, хоч променем сонця полину,
І легенько війну над твоїм, Україно, лицем.
Приспів.','[''pisni.org.ua'', ''cat:devoted'', ''cat:nostalgia'', ''Пісні присвячені окремим особам'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_812552'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_812552','У райськім саду','Я на світі прожив, наче спалах зорі на світанні,
