INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8128219','Через ліс, через ліс','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Цю пісню співають у нас в сім''ях',NULL,'Через ліс, через ліс
Треба нам, малята,
Щоб грибів, щоб грибів
В лісі назбирати.

На місточку вовчик спочиває,
Він до лісу діток не пускає.

Він гарчить, він гарчить,
Клацає зубами:
Не пущу, не пущу
Діток за грибами!

Вийшов козлик з зеленого гаю,
Він сердито вовчику гукає:

Заколю, заколю
Я тебе рогами,
Затопчу, затопчу
Я тебе ногами!

Як ударив вовчика рогами -
покотився вовчик в воду прямо!

Ми йдемо, ми йдемо
Мостом через річку,
Несемо, несемо
Козлику травичку:

Ой, спасибі, козлику рогатий,
Що поміг нам вовчика прогнати!','[''pisni.org.ua'', ''cat:dytyachi'', ''cat:zhartivlyvi'', ''Дитячі пісні'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8128219'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8128219','Через ліс, через ліс','Через ліс, через ліс
Треба нам, малята,
Щоб грибів, щоб грибів
В лісі назбирати.

На місточку вовчик спочиває,
Він до лісу діток не пускає.

Він гарчить, він гарчить,
Клацає зубами:
Не пущу, не пущу
Діток за грибами!

Вийшов козлик з зеленого гаю,
Він сердито вовчику гукає:

Заколю, заколю
Я тебе рогами,
Затопчу, затопчу
Я тебе ногами!

Як ударив вовчика рогами -
покотився вовчик в воду прямо!

Ми йдемо, ми йдемо
Мостом через річку,
Несемо, несемо
Козлику травичку:

Ой, спасибі, козлику рогатий,
Що поміг нам вовчика прогнати!');
