INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8125654','Мете...','Музика: Тризубий Стас Слова: Тризубий Стас. Виконує: Тризубий Стас','uk','ukraine_1991',NULL,NULL,'http://ukrmusic.com.ua',NULL,'Мете...
Вихрить за вікнами, гуде, мете...
Мете...
А на душі — ні се, ні те.
Мете...
А ви, напевно, вже спите, спите...
Ми бачились два тижні.
Ви були такі ніжні...
Тепер те все пусте.

Я вас три місяці не виджу,
Бо я у Львові, ви — в Парижу.
На сторінках "Юманіте"
Друкують ваше декольте.
А в нас мете...

Несе...
На мене вітер білий сніг несе.
Несе мене на "Ладі" по шосе.
Несе...
А на душі моїй — ні те, ні се...
І серце — як лелека,
Бо ви є так далеко...
Набридло те усе!

Та я поїду до Парижу,
Я свою мрію не облишу.
У вас там "парлі ву франсе
І пуркуа, і кес ке се",
А в нас несе...

Жене мене за нею у турне дурне,
Жене у карбюраторі пальне.
Жене...
Невже кохана бортане мене?
Невже мене не прийме
В палкі свої обійми,
А візьме й лажане?...

Та я дістанусь до Парижу,
Нехай на тім зароблю грижу!
І ваше серце крижане
Розтопить пляшка "Каберне", чи "Сам жене"...

Паде...
Автодвірник танцює
Па-де-де...
Паде...
Мабуть, не їду я ніде.
Паде...
О''ревуар, мадам,
Мерсі гранде!
Додому повертаю,
А в мене у сараю
Вже цеглу хтось краде...

Я ще колись буду в Парижу,
Чи, може, там листа напишу.
І, хоч Париж той бозна-де,
Та, може, лист мій і дійде...
... А в нас паде','[''pisni.org.ua'', ''cat:bardivski'', ''Бардівські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8125654'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8125654','Мете...','Мете...
