INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_813450','Ой у вишневому садку','Українська народна пісня. Виконує: Ніна Матвієнко, Наталія Бучинська, Діана Петриненко, Таїсія Повалій','uk','ukraine_before_1917',NULL,NULL,NULL,'Акорди (варіант 2) надав Данило','Ой у вишневому садку
Там соловейко щебетав
Додому я просилася           |
Gm       |
А ти мене все не пускав.     | (2)
"Ти милий мій, а я твоя.
Пусти мене, зійшла зоря.
Проснеться матінка моя,      |
Буде питать, де була я."     | (2)
А ти їй дай такий отвіт:
"Яка прекрасна майська ніч.
Весна іде, красу несе,       |
І тій красі радіє все."      | (2)
"Доню моя, не в тому річ.
Де ти блукала цілу ніч?
Чому розплетена коса,        |
А на очах блистить сльоза?"  | (2)
"Коса моя розплетена -
Її подруги розплели.
А на очах блистить сльоза,   |
Бо з милим я прощалася.      | (2)
Мамо моя, ти вже стара,
А я щаслива, молода.
Я жити хочу, я люблю.        |
Мамо, не лай доню свою."     | (2)
варіант 2:
Ой у вишневому садку
Там соловейко щебетав
Додому я просилася           |
Em       |
А ти мене все не пускав.     | (2)','[''pisni.org.ua'', ''cat:lirychni'', ''cat:narodni'', ''Пісні про кохання, ліричні'', ''Народні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_813450'), datetime('now')),datetime('now'));
