INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8130154','Чорний рояль','Музика: Мар''ян Гаденко Слова: Зоя Кучерява. Виконує: Фемій Мустафаєв','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Знову весна, радості час,
Все навкруги сяє для нас,
Сонячний дощ, неба кришталь,
Сцена і зал, я і рояль.

Приспів:
Просить душа: "Пісню співай!"
Знає душа, що таке рай,
Ангеле мій, доле моя,
В серці звучить чорний рояль.
Чорний рояль, чорний рояль,
В серці звучить музика знов,
Тихо з плечей падає шаль,
Я і рояль, ти і любов.

Музика нам світить давно,
Щастя п''янить, наче вино,
Ангеле мій, доле моя,
Слухає нас тільки рояль.

Приспів.','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8130154'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8130154','Чорний рояль','Знову весна, радості час,
Все навкруги сяє для нас,
