INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8132714','Марш ліцеїстів юридичного ліцею ім. Яр.Кондратьєва','Музика: Володимир Гриньків Слова: Володимир Мельников. Виконує: Хор ліцею','uk','ukraine_1991',NULL,'2009',NULL,'Марш ліцеїстів юридичного ліцею ім. Ярослава Кондратьєва Київського національного університету внутрішніх справ на слова заслуженого діяча мистецтв Володимира Мельникова та музику Володимира Гриньківа у виконанні хору ліцею вперше було виконано 26.09.2009 з нагоди посвяти першокурсників у ліцеїсти та святкування 10-ї річниці створення юридичного ліцею. Виконує:Хор ліцею','Ми з різних регіонів приїхали в ліцей,
Обравши шлях в міліції служити.
І хай не всім під силу життєвий вибір цей,
Ми мусимо цей вибір заслужити!

Приспів:
Юридичний ліцей МВС України
Ярослава Кондратьєва носить ім''я.
Юридичний ліцей - це наш дім і родина,
Ліцеїсти - надійна і дружна сім''я.

Навчатися у Києві таланить не усім.
Кондратьєвці! Уславимо країну -
Старанням у навчанні, але передусім
Навчимося любити Україну!

Приспів.

Здолаємо науки і навіть власну лінь.
Фізичні вправи зроблять нас міцніше,
А нашим педагогам - подяка і уклін!
Немає у ліцеї вас рідніше.

Приспів','[''pisni.org.ua'', ''cat:himny-marshi'', ''Гимни та марші'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8132714'), datetime('now')),datetime('now'));
