INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8131807','Не віддавай нікому цеї ночі','Музика: Ліля Кобільник Слова: Марія Матіос. Виконує: Ліля Кобільник','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Прийшла до мене ти із круговерті,
А я люблю тебе, тебе люблю
Всі інші з пам''яті моєї стерті
Без боязні, без муки, без жалю.

Приспів:
Не віддавай нікому цеї ночі,
Ні дня, ні сну, ні цілого життя.
Без тебе жити серце вже не хоче,
Не може серце без твого ім''я.
Летить Земля у космос чи у прірву, -
А ми зробім собі маленький рай,
Бо я тебе із серця вже не вирву
І ти мене з душі не виривай!

Люблю тебе до смерті чи до рана,
Але навіки я уже твоя.
Почнеться день твоїм ім''ям, коханий,
Покличе ніч: "О, ліліє моя..."

Приспів.','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8131807'), datetime('now')),datetime('now'));
