INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8136474','Хлопці кучеряві','Українська народна пісня. Виконує: Алла Кудлай','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Хлопці кучеряві, не ходіть до нас,
Бо вже поламали браму й перелаз.
І не знає мати, як вас відігнать,    |
Бо їй до світанку не даєте спать.    | (2)

Через вас у мене голова болить,
Через вас не буде Василько ходить.
У очах у нього ранок голубий,        |
І такі цілунки, як вогонь палкий.    | (2)

Не ходіть до ранку край мого села -
Не туди стежина ваша пролягла.
На усіх не стане в мене теплих слів, |
На усіх не буде в мене гарбузів.     | (2)

Хлопці кучеряві, не ходіть до нас,
Бо вже поламали браму й перелаз.
Як відчарувати, що мені робить?      |
Всіх вас поцілую, тільки не ходіть!  | (2)','[''pisni.org.ua'', ''cat:dances'', ''cat:polky'', ''cat:zhartivlyvi'', ''Пісні до танцю'', ''Польки'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8136474'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8136474','Хлопці кучеряві','Хлопці кучеряві, не ходіть до нас,
Бо вже поламали браму й перелаз.
І не знає мати, як вас відігнать,    |
Бо їй до світанку не даєте спать.    | (2)

Через вас у мене голова болить,
Через вас не буде Василько ходить.
У очах у нього ранок голубий,        |
І такі цілунки, як вогонь палкий.    | (2)

Не ходіть до ранку край мого села -
Не туди стежина ваша пролягла.
На усіх не стане в мене теплих слів, |
На усіх не буде в мене гарбузів.     | (2)

Хлопці кучеряві, не ходіть до нас,
