INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8144575','Шукала тебе','Музика: Антоніо Гальбіаті Слова: Оксана Голуб. Виконує: Оксана Голуб','uk','ukraine_1991',NULL,NULL,'Продюсер',NULL,'Якщо колись заблукаєш в вирі днів,
Свої крила ти не складай.
Згадай усе, що любив,
Двері щастю ти не закривай.
І незважаючи, що у серці біль
Пече, руйнує твоє життя,
Мені повір, і впусти
В змучене серце нові почуття.

Приспів:
Ніжним подихом весни
Огорне любов усе твоє життя
І у серці твоїм залишусь я, залишусь я.
Завтра буде день новий,
І, можливо, хтось свою любов знайде
Так, як в світі надій,
Шукала я тебе.

2.
Якщо печаль твоє серце знов знайде -
Огорну я його крильми -
Той біль відступить, і все
Буде так, як захочемо ми.
Бо коли любиш, сердець вогонь
Не загасити лихим вітрам.
Ти доторкнешся моїх долонь,
А я любов тобі віддам.

Приспів:
Ніжним подихом весни
Ти зігрій тоді усе моє життя
І у серці твоїм залишусь я, залишусь я.
Завтра буде день новий,
І, можливо, хтось свою любов знайде
Так, як в світі надій,
Шукала я тебе.

Приспів:
Ніжним подихом весни
Ти зігрій тоді усе моє життя
І у серці твоїм палким вогнем залишусь я.
Завтра буде день новий,
І, можливо, хтось свою любов знайде
Так, як в світі надій,
Знайшла тебе','[''pisni.org.ua'', ''cat:all-ukraine'', ''Загальноукраїнські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8144575'), datetime('now')),datetime('now'));
