INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_81474','Посаджу я грушечку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'А вже весна скресла. Збірник гаївок. Львів, 2003.','Дівчата стають півколом, не беручись за руки. Усі виконують рухи до слів пісні. Одна стоїть посередині й показує рухи докладніше. На слова "Росте, росте..." руки підносять вгору, "цвіте" — описують дію над головою.','Посаджу я грушечку: гай  буде, гай.
Нічко моя темная, і ти, зоре ясная,
Дай, Боже, дай.

Росте грушечка...
Зацвила грушечка...
Уродила грушечка...
Я скуштую грушечку...    Мелодія для 1 голосу','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_81474'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_81474','Посаджу я грушечку','Посаджу я грушечку: гай  буде, гай.
