INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_813909','Лист додому','Музика: Дмитро Добрий-Вечір Слова: Дмитро Добрий-Вечір. Виконує: Вій','uk','ukraine_1991',NULL,NULL,NULL,'Підбір акордів: Я','Є наказ війти у село,
Є наказ не брати в полон.
Ця війна для справжніх солдатів,
Для чоловіків.

Із селом палає земля,
Мов зірки на вежах Крeмля.
Це село, що лігво звірине,
Повне ворогів.

Три дні не милися та не голилися,
Горами рачки лізли ми та болотами повзли,
Лісами кралися та все молилися,
Молились Богу ми і чорту,
Щоб нарешті дійти.

Як полізли ті вороги
На всі боки, мов таргани,
Постріляли ми з гранатометів
Всіх, хто був живий.

Три дні не милися та не голилися,
Горами рачки лізли ми та болотами повзли,
За революцію, за конституцію,
За президента "ДО ПОБЕДНОГО"
Вбивали та вмирали самі.

У кишені фото лежить,
Мамо люба, ти ще не спиш?

Мамо, я маю вбити ту жінку,
Що іще біжить.

Три дні не мився я, та не голився я,
Горами рачки, мамо, ліз, та болотами я повз.
Лісами крався я, та все молився я,
Молився Богу я і чорту,
Тож нарешті дійшов!

Три дні не миюсь я та не голюся я,
Горами рачки лізу я та болотами повзу.
Я революція, я конституція,
Я президент, я контингент,
Гарматне м''ясо та народний герой!','[''pisni.org.ua'', ''cat:himny-marshi'', ''Гимни та марші'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_813909'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_813909','Лист додому','Є наказ війти у село,
Є наказ не брати в полон.
Ця війна для справжніх солдатів,
Для чоловіків.

Із селом палає земля,
Мов зірки на вежах Крeмля.
Це село, що лігво звірине,
Повне ворогів.

Три дні не милися та не голилися,
Горами рачки лізли ми та болотами повзли,
Лісами кралися та все молилися,
Молились Богу ми і чорту,
