INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8139777','Святий Миколай','Музика: Леся Соболевська Слова: Леся Соболевська. Виконує: Майя Негребецька','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Нічка-чарівничка глянула у шибку.
Я затулю вічка та засну не швидко.
Вдень була я чемна, бо сьогодні, знаю,
Що для чемних діток є дарунки
В святого Миколая.

Приспів:
Ходить по землі святий Миколай,
Тільки ти засни і його чекай.
Ти лише повір в те, що він прийде,
Якщо будеш ти добрим до людей.

Уночі на небі зіронька засяє.
Чарівник ласкавий в гості завітає.
А ясного ранку під подушку гляну
І від Миколая подарунок
З радістю дістану.

Приспів.

Хочу в Миколая щиро попросити,
Щоб чарівна казка панувала в світі,
Щоб не обминула жодної хатини,
Бо її чекає з нетерпінням
Кожная дитина.

Приспів.','[''pisni.org.ua'', ''cat:dytyachi'', ''cat:svyatyy-mykolay'', ''Дитячі пісні'', ''Пісні про Святого Миколая'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8139777'), datetime('now')),datetime('now'));
