INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_81450','Шум','(Гей нумо-нумо заплетімо Шума). Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1991','А вже весна скресла. Збірник гаївок. Львів, 2003.','Записано 1998 року під час фольклорно-етнографічної експедиції "Джерела Божої криниці" від Греви Анни (с. Розжалів Радехівського району Львівської області). Опис гри: Пісня і рух ідуть щораз швидшим темпом. Плетінкою заходять усі в лінію колеса. Повторюється пісня 2 рази. (Джерело: Свято гаївок: великодні, весняні пісні та ігри.– Дрогобич: Бескид, 1991.– 52 c.)','Гей нумо-нумо заплетімо Шума.
Шума заплетімо, гуляти ходімо.

Приспів:
Ой ходить Шум по діброві,
А Шумиха рибу ловить,
Що зловила, те пропила,
Сукні дочці не купила:
"Постій, дочко, до суботи,
Куплю тобі ще й чоботи,
Червоную плахту, зелену запаску."
Люби мене, козаченьку, коли твоя ласка.

Гей нумо-нумо в зеленого Шума.
А в нашого Шума зеленая шуба.

Приспів.

Гей заплетися, Шуме, заплетися,
Та зеленим барвіночком розстелися.

Приспів.

Гей нумо-нумо розплетімо Шума.
Шума розплетімо, гуляти ходімо.    Мелодія для 1 і 2 голосу','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_81450'), datetime('now')),datetime('now'));
