INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8150272','Дума Волоха','Музика: Кирило Стеценко Слова: Тарас Шевченко. Виконує: Борис Гмиря, Павло Кармалюк','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ой, волохи, волохи,
Вас зосталося трохи.
І ви, молдавани,
Тепер ви - не пани!

Ваші господарі -
Наймити татарам,
Турецьким султанам
В кайданах, в кайданах!

Годі ж, не журіться,
Гарно помоліться,
Братайтеся з нами,
З нами, козаками!

Згадайте Богдана,
Славного гетьмана -
Будете панами.
Та, як ми, з ножами.

Та з батьком Максимом
Сю ніч погуляєм,
Шляхту погойдаєм,
Добре погуляєм!
Гей! Гей-ге-гей!','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8150272'), datetime('now')),datetime('now'));
