INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8154474','Ой, горіла біла корчма','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Kulik A., Pleśniak P. Dla Oli na słowiańską nutę. Wybrane pieśni łemkowskie, bojkowskie, słowackie, polskie i inne. - Mińsk Mazowiecki, 2001. – 16 p.',NULL,'Ой, горіла, біла корчма горіла,
Ой, горіла, біла корчма горіла,
Аж до видня моя мила сиділа,
У фартушку зимну воду носила,
У фартушку зимну воду носила,
А та вода білу корчму гасила.

Ой, почекай, младий корчмар то зробіл,
Ой, почекай, младий корчмар то зробіл,
І це треба до палінки лять воду,
І не змішав паліночку з водою,
І не змішав паліночку з водою,
Запалили білу корчму так.

Ой, горіла, біла корчма горіла,
Ой, горіла, біла корчма горіла,
А так мила білу корчму гасила.','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8154474'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8154474','Ой, горіла біла корчма','Ой, горіла, біла корчма горіла,
